import numpy as np
from scipy.signal import find_peaks
from decimal import Decimal, ROUND_HALF_UP
from scipy.signal import sawtooth


def process_output(x, decimal_place, method="median", round_number=True):
    """
    Process an array-like input to compute a summary statistic (median, mean, or standard deviation),
    remove NaN values, and round the result as specified.

    Parameters
    ----------
    x : array-like
        One-dimensional array of numerical values.
    decimal_place : int
        Number of decimal places to round the output if round_number is False.
    method : str, optional
        The summary statistic to compute. Must be one of {"median", "mean", "sd"}.
        Defaults to "median".
    round_number : bool, optional
        If True, round the output to the nearest integer. If False, round to the specified decimal place.
        Defaults to True.

    Returns
    -------
    int, Decimal, or None
        The processed value (rounded as specified), or None if input is empty after removing NaNs.

    Examples
    --------
    >>> process_output([1, 2, 3, np.nan], 2, round_number=False)
    Decimal('2.00')
    >>> process_output([1, 2, 3, np.nan], 0, round_number=True)
    2
    >>> process_output([1, 2, 3, 4], 1, method="mean", round_number=False)
    Decimal('2.50')
    >>> process_output([1, 2, 3, 4], 0, method="sd", round_number=True)
    1
    """
    x = np.asarray(x)
    x = x[~np.isnan(x)]
    if len(x) == 0:
        return None

    if method == "mean":
        output = np.mean(x)
    elif method == "median":
        output = np.median(x)
    elif method == "sd":
        output = np.std(x)

    if round_number:
        output = int(Decimal(output).to_integral_value(rounding=ROUND_HALF_UP))
    else:
        quantize_str = "1." + "0" * decimal_place
        output = Decimal(str(output)).quantize(
            Decimal(quantize_str), rounding=ROUND_HALF_UP
        )

    return output


def find_max_peak(x, y, x_band=None):
    """
    Find the maximum peak in y within the x_band range of x.

    Parameters
    ----------
    x : np.ndarray
        1D array of x values (e.g., frequency).
    y : np.ndarray
        1D array of y values (e.g., magnitude).
    x_band : tuple or list, optional
        (min, max) range for x to consider. If None, uses the full range (-inf, inf).

    Returns
    -------
    peak_x : float
        x value of the maximum peak, or np.nan if no peak found.
    peak_y : float
        y value of the maximum peak, or np.nan if no peak found.

    Examples
    --------
    >>> x = np.linspace(0, 10, 100)
    >>> y = np.sin(x)
    >>> find_max_peak(x, y, x_band=(2, 8))
    (6.343434343434343, 0.9994862162006879)
    """
    x = np.asarray(x)
    y = np.asarray(y)
    if x_band is None:
        x_band = (-np.inf, np.inf)
    mask = (x >= x_band[0]) & (x <= x_band[1])
    x_sel = x[mask]
    y_sel = y[mask]

    if len(x_sel) == 0 or len(y_sel) == 0:
        return np.nan, np.nan

    peaks, _ = find_peaks(y_sel, height=0)
    if len(peaks) == 0:
        return np.nan, np.nan

    max_idx = peaks[np.argmax(y_sel[peaks])]
    return x_sel[max_idx], y_sel[max_idx]


def min_max_scale(data, feature_range=(0, 1), data_range=(None, None)):
    """
    Scale the input data to the given feature range using min-max normalization.

    The formula used is:
        scaled = a + (x - min_val) * (b - a) / (max_val - min_val)
    where:
        - x is the original value,
        - min_val and max_val are the minimum and maximum of the input data (or provided data_range),
        - (a, b) is the desired feature_range.

    Parameters
    ----------
    data : array-like
        Input data to be scaled.
    feature_range : tuple of (float, float), optional
        Desired range of transformed data (min, max). Default is (0, 1).
    data_range : tuple of (float or None, float or None), optional
        The (min, max) values to use for scaling. If (None, None), uses the min and max of the input data.

    Returns
    -------
    np.ndarray
        Scaled data within the specified feature range.

    Examples
    --------
    >>> min_max_scale([1, 2, 3], feature_range=(0, 1))
    array([0. , 0.5, 1. ])
    >>> min_max_scale([1, 2, 3], feature_range=(-1, 1))
    array([-1.,  0.,  1.])
    >>> min_max_scale([1, 2, 3], feature_range=(0, 1), data_range=(1, 3))
    array([0. , 0.5, 1.])
    """
    data = np.asarray(data)
    if data_range == (None, None):
        min_val, max_val = np.min(data), np.max(data)
    else:
        min_val, max_val = data_range
    a, b = feature_range
    scaled = a + (data - min_val) * (b - a) / (max_val - min_val)
    return scaled


def normalize_to_distribution(data, target=(0, 1), original=(None, None)):
    """
    Normalize the input data to have a specified mean and standard deviation.

    The formula used is:
        normalized = (x - original_mean) / original_std * target_std + target_mean
    where:
        - x is the original value,
        - original_mean and original_std are the mean and standard deviation of the input data
          (or provided in `original`),
        - target_mean and target_std are the desired mean and standard deviation (from `target`).

    Parameters
    ----------
    data : array-like
        Input data to be normalized.
    target : tuple of (float, float), optional
        Desired (mean, std) of the output data. Default is (0, 1).
    original : tuple of (float or None, float or None), optional
        The (mean, std) values to use for normalization. If (None, None),
        uses the mean and std of the input data.

    Returns
    -------
    np.ndarray
        The normalized data with the specified mean and standard deviation.

    Raises
    ------
    ValueError
        If the standard deviation of the input data (after resolution) is zero.
    """
    data = np.asarray(data, dtype=float)

    target_mean, target_std = target
    orig_mean, orig_std = original

    # compute any missing original stats
    if orig_mean is None:
        orig_mean = np.mean(data)
    if orig_std is None:
        orig_std = np.std(data)  # ddof=0 by default

    if orig_std == 0:
        raise ValueError(
            "Standard deviation of the input data is zero. Cannot normalize."
        )

    # apply normalization
    normalized = (data - orig_mean) / orig_std * target_std + target_mean
    return normalized


def sliding_window_multi(window_size, step, *arrays):
    """
    Generate sliding windows from multiple aligned arrays.

    Parameters
    ----------
    window_size : int
        Number of rows in each window.
    step : int
        Step size (number of rows to move the window).
    *arrays : one or more np.ndarray
        One or more arrays with the same number of rows. Each array should be at least 2D (shape: (n_rows, n_cols)).

    Yields
    ------
    tuple of np.ndarray
        A tuple containing a slice from each input array of shape (window_size, n_cols).

    Raises
    ------
    ValueError
        If no arrays are provided or if arrays do not have the same number of rows.

    Examples
    --------
    >>> data1 = np.random.rand(10, 2)
    >>> data2 = np.random.rand(10, 2)
    >>> for win_data1, win_data2 in sliding_window_multi(5, 2, data1, data2):
    ...     print(win_data1.shape, win_data2.shape)
    (5, 2) (5, 2)
    (5, 2) (5, 2)
    (5, 2) (5, 2)
    (5, 2) (5, 2)
    """
    if not arrays:
        raise ValueError("At least one array must be provided.")

    length = arrays[0].shape[0]
    if not all(arr.shape[0] == length for arr in arrays):
        raise ValueError("All arrays must have the same number of rows.")

    for i in range(0, length - window_size + 1, step):
        yield tuple(arr[i : i + window_size, :] for arr in arrays)


class DisplayReadings:
    """
    Class for determining the display label for sensor readings based on quality metrics.

    This class provides logic to decide whether sensor readings (e.g., SpO2, heart rate)
    should be labeled as "good" or "poor" for display, based on configurable thresholds
    and input parameters. It currently supports logic for finger mode and can be extended
    for other sensor modes.

    Parameters
    ----------
    params_finger : dict, optional
        Dictionary of threshold parameters for finger mode. If not provided, default
        thresholds are used.

    Attributes
    ----------
    params_finger : dict
        Thresholds for accepted SpO2 frames and signal variation.

    Methods
    -------
    init_params_finger()
        Initialize default threshold parameters for finger mode.
    decide_display_label(sensor_mode, **kwargs)
        Decide the display label ("good" or "poor") based on input metrics and sensor mode.

    Examples
    --------
    >>> dr = DisplayReadings()
    >>> label = dr.decide_display_label(
    ...     sensor_mode='finger',
    ...     spo2=98,
    ...     hr=75,
    ...     accepted_spo2_frame=10,
    ...     signal_variation=0.5,
    ...     skin_contact=1
    ... )
    >>> print(label)
    1  # good
    """

    def __init__(self, params_finger=None):
        if params_finger is not None:
            self.params_finger = params_finger
        else:
            self.params_finger = self.init_params_finger()

    def init_params_finger(self):
        return {
            "threshold_accepted_spo2_frame": 8,
            "threshold_signal_variation": 0.4,
        }

    def decide_display_label(self, sensor_mode, **kwargs):

        if sensor_mode == "finger":
            spo2 = kwargs.get("spo2")
            hr = kwargs.get("hr")
            accepted_frame_spo2 = kwargs.get("accepted_spo2_frame")
            val_sd_signal_w_sqa = kwargs.get("signal_variation")
            skin_contact = kwargs.get("skin_contact")

            if (spo2 is not None) and (hr is not None):
                if (
                    (
                        accepted_frame_spo2
                        >= self.params_finger["threshold_accepted_spo2_frame"]
                    )
                    and (
                        val_sd_signal_w_sqa
                        >= self.params_finger["threshold_signal_variation"]
                    )
                    and (skin_contact == 1)
                ):
                    label = 1  # good
                else:
                    label = 0  # poor
            else:
                return 0  # poor
        elif sensor_mode == "chest":  # TODO: implement logic for chest mode later
            print("Pending implementation for RR mode")
        else:
            raise ValueError("Invalid sensor mode. Must be 'HR' or 'RR'.")

        return label


def generate_sawtooth_template(length, frequency=1, amplitude=1, sampling_rate=100):
    """
    Generate a sawtooth wave template.

    A sawtooth wave is a periodic waveform that rises linearly from -amplitude to +amplitude
    and then drops sharply back to -amplitude. This function generates a discrete sawtooth
    signal of specified length, frequency, and amplitude.

    Parameters
    ----------
    length : int
        Number of samples in the output template.
    frequency : float, optional
        Frequency of the sawtooth wave in Hz. Default is 1.
    amplitude : float, optional
        Peak amplitude of the sawtooth wave. The wave oscillates between
        -amplitude and +amplitude. Default is 1.
    sampling_rate : int or float, optional
        Sampling rate in Hz (samples per second). Default is 100.

    Returns
    -------
    np.ndarray
        1D array of length `length` containing the sawtooth wave samples.

    Examples
    --------
    >>> # Generate a 1 Hz sawtooth wave with 100 samples at 100 Hz sampling rate
    >>> template = generate_sawtooth_template(100, frequency=1, amplitude=1, sampling_rate=100)
    >>> template.shape
    (100,)
    >>> np.min(template), np.max(template)
    (-1.0, 0.9797979797979798)

    >>> # Generate a 2 Hz sawtooth wave with amplitude 5
    >>> template = generate_sawtooth_template(200, frequency=2, amplitude=5, sampling_rate=100)
    >>> template.shape
    (200,)
    >>> round(np.min(template), 1), round(np.max(template), 1)
    (-5.0, 5.0)
    """
    t = np.linspace(0, length / sampling_rate, length)
    template = amplitude * sawtooth(2 * np.pi * frequency * t)
    return template



def has_n_consecutive(values, n=5, target=1):
    """
    Return True if `values` contains at least `n` consecutive elements equal to `target`.
    """
    count = 0
    for v in values:
        if v == target:
            count += 1
            if count >= n:
                return True
        else:
            count = 0
    return False